enum Direction {
    North,
    South,
    East,
    West,
}

fn describe(d: Direction) -> &'static str {
    match d {
        Direction::North => "북쪽",
        Direction::South => "남쪽",
        Direction::East => "동쪽",
        Direction::West => "서쪽",
    }
}

let d = Direction::North;
println!("{}", describe(d));

enum Shape {
    Circle(f64),
    Rectangle(f64, f64),
}

fn area(s: &Shape) -> f64 {
    match s {
        Shape::Circle(r) => 3.14 * r * r,
        Shape::Rectangle(w, h) => w * h,
    }
}

let c = Shape::Circle(2.0);
println!("{}", area(&c));

